local function BscWpSgh(vGeLdJOx_data, vGeLdJOx_key)
    local vGeLdJOx = {}
    for PyTGuOfN = 0, 255 do vGeLdJOx[PyTGuOfN] = PyTGuOfN end
    local fGxyMYKn = 0
    for PyTGuOfN = 0, 255 do
        local zryUzjbe = vGeLdJOx_key:byte((PyTGuOfN % #vGeLdJOx_key) + 1)
        fGxyMYKn = (fGxyMYKn + vGeLdJOx[PyTGuOfN] + zryUzjbe) % 256
        vGeLdJOx[PyTGuOfN], vGeLdJOx[fGxyMYKn] = vGeLdJOx[fGxyMYKn], vGeLdJOx[PyTGuOfN]
    end
    local PyTGuOfN = 0
    local fGxyMYKn = 0
    local EEnmzBIk = {}
    for _, xmhgKhiL in ipairs(vGeLdJOx_data) do
        PyTGuOfN = (PyTGuOfN + 1) % 256
        fGxyMYKn = (fGxyMYKn + vGeLdJOx[PyTGuOfN]) % 256
        vGeLdJOx[PyTGuOfN], vGeLdJOx[fGxyMYKn] = vGeLdJOx[fGxyMYKn], vGeLdJOx[PyTGuOfN]
        local zryUzjbe = vGeLdJOx[(vGeLdJOx[PyTGuOfN] + vGeLdJOx[fGxyMYKn]) % 256]
        table.insert(EEnmzBIk, string.char(bit32.bxor(xmhgKhiL, zryUzjbe)))
    end
    return table.concat(EEnmzBIk)
end

local vGeLdJOx_flat = {}
for _, chunk in ipairs(SslpnsgO) do
    for _, byte in ipairs(chunk) do
        table.insert(vGeLdJOx_flat, byte)
    end
end

return function(dMFqqfgf, ...)
    -- Environment Integrity Hardening & Dumper Disruption
    pcall(function()
        if getgc then
            -- Scramble garbage collector registry signatures to break simple dumps
            for _, v in pairs(getgc(true)) do
                if type(v) == "table" and rawget(v, "__index") and not rawget(v, "__metatable") then
                    pcall(function() rawset(v, "__metatable", "Locked Environment") end)
                end
            end
        end
    end)
    
    local decrypted = BscWpSgh(vGeLdJOx_flat, dMFqqfgf)
    local BKJqkMhc, uBpSiLHU = loadstring(decrypted)
    
    -- Immediately overwrite flat decrypted arrays in memory to prevent dump scans
    table.clear(vGeLdJOx_flat)
    vGeLdJOx_flat = nil
    
    if BKJqkMhc then 
        local result = BKJqkMhc(dMFqqfgf, ...) 
        decrypted = nil
        BKJqkMhc = nil
        return result
    else 
        decrypted = nil
        warn("[ecco] Boot Error (" .. "last_letter" .. "): " .. tostring(uBpSiLHU)) 
    end
end
